 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import { FirehoseResource } from '@openshift-console/dynamic-plugin-sdk';
 4	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 5	import { RecentEventsBody } from '@openshift-console/dynamic-plugin-sdk-internal';
 6	import { EventKind } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/internal-types';
 7	import classNames from 'classnames';
 8	import {
 9	  Card,
10	  CardBody,
11	  CardHeader,
12	  CardProps,
13	  CardTitle,
14	} from '@patternfly/react-core';
15	import './GeneralOverviewActivityCard.scss';
16	
17	const eventsResource: FirehoseResource = {
18	  isList: true,
19	  kind: 'Event',
20	  prop: 'events',
21	};
22	
23	export const GeneralOverviewActivityCard: React.FC<CardProps> = ({
24	  className,
25	}) => {
26	  const { t } = useCustomTranslation();
27	  const [data, loaded, loadError] =
28	    useK8sWatchResource<EventKind[]>(eventsResource);
29	
30	  return (
31	    <Card
32	      className={classNames(className, 'odf-general-overview__activity-card')}
33	      isFlat={true}
34	    >
35	      <CardHeader>
36	        <CardTitle>{t('Activity')}</CardTitle>
37	      </CardHeader>
38	      <CardBody className="odf-general-overview__activity-card-body">
39	        <RecentEventsBody
40	          events={{
41	            data,
42	            loaded,
43	            loadError,
44	          }}
45	        />
46	      </CardBody>
47	    </Card>
48	  );
49	};

